import { Component } from '@angular/core';

@Component({
  selector: 'app-header',
  templateUrl: './header.component.html',
  styleUrls: ['./header.component.scss']
})
export class HeaderComponent {}
<div class="app-header">
  <img alt="logo" src="assets/logo.svg">
  <!-- using class right for flex design to keep username and login/logout button to the right side-->
  <div class="right">
    <ng-content select=".username"></ng-content> <!-- using select method to select username class from app component-->
    <ng-content select=".login-btn"></ng-content> <!-- using select method to select login-btn class from app component-->
  </div>
</div>
